Here is a simple C++ code that can guess a number from 0 to 100 with user input and give the hint whether the number is higher or lower than the guess.

```
#include <iostream>
#include <cstdlib>
#include <ctime>

using namespace std;

int main()
{
    srand(time(NULL)); // Set the seed for random number generator
    int number = rand() % 101; // Generate a random number from 0 to 100

    int guess = 0;
    int attempts = 0;

    while(guess != number)
    {
        cout << "Guess a number between 0 to 100: ";
        cin >> guess;
        attempts++;

        if(guess > number)
        {
            cout << "Too high! Try a smaller number." << endl;
        }
        else if(guess < number)
        {
            cout << "Too low! Try a bigger number." << endl;
        }
    }

    cout << "Congratulations! You guessed the number " << number << " in " << attempts << " attempts." << endl;

    return 0;
}
```

This code sets the seed for the random number generator to the current time to make the generated numbers more unpredictable. It then generates a random number from 0 to 100 and prompts the user to guess the number. 

The code then checks if the guessed number is higher or lower than the correct number, and gives the corresponding hint. The program loops until the user guesses the correct number, at which point it will congratulate the user and tell them how many attempts it took to guess the correct number.

Here is an example C++ code for a simple Snake game:

```
#include <iostream>
#include <conio.h>
#include <windows.h>
using namespace std;

bool gameOver;
const int width = 20;
const int height = 20;
int x, y, fruitX, fruitY, score;
int tailX[100], tailY[100];
int nTail;
enum eDirection { STOP = 0, LEFT, RIGHT, UP, DOWN };
eDirection dir;

void Setup()
{
    gameOver = false;
    dir = STOP;
    x = width / 2;
    y = height / 2;
    fruitX = rand() % width;
    fruitY = rand() % height;
    score = 0;
}

void Draw()
{
    system("cls");
    cout << "Score: " << score << endl;
    for (int i = 0; i < width + 2; i++)
        cout << "#";
    cout << endl;

    for (int i = 0; i < height; i++)
    {
        for (int j = 0; j < width; j++)
        {
            if (j == 0)
                cout << "#";
            if (i == y && j == x)
                cout << "O";
            else if (i == fruitY && j == fruitX)
                cout << "F";
            else
            {
                bool print = false;
                for (int k = 0; k < nTail; k++)
                {
                    if (tailX[k] == j && tailY[k] == i)
                    {
                        cout << "o";
                        print = true;
                    }
                }
                if (!print)
                    cout << " ";
            }

            if (j == width - 1)
                cout << "#";
        }
        cout << endl;
    }

    for (int i = 0; i < width + 2; i++)
        cout << "#";
    cout << endl;
}

void Input()
{
    if (_kbhit())
    {
        switch (_getch())
        {
        case 'a':
            dir = LEFT;
            break;
        case 'd':
            dir = RIGHT;
            break;
        case 'w':
            dir = UP;
            break;
        case 's':
            dir = DOWN;
            break;
        case 'x':
            gameOver = true;
            break;
        }
    }
}

void Logic()
{
    int prevX = tailX[0];
    int prevY = tailY[0];
    int prev2X, prev2Y;
    tailX[0] = x;
    tailY[0] = y;
    for (int i = 1; i < nTail; i++)
    {
        prev2X = tailX[i];
        prev2Y = tailY[i];
        tailX[i] = prevX;
        tailY[i] = prevY;
        prevX = prev2X;
        prevY = prev2Y;
    }

    switch (dir)
    {
    case LEFT:
        x--;
        break;
    case RIGHT:
        x++;
        break;
    case UP:
        y--;
        break;
    case DOWN:
        y++;
        break;
    default:
        break;
    }
    //if (x > width || x < 0 || y > height || y < 0)
        //gameOver = true;

    if (x >= width) x = 0; else if (x < 0) x = width - 1;
    if (y >= height) y = 0; else if (y < 0) y = height - 1;

    for (int i = 0; i < nTail; i++)
        if (tailX[i] == x && tailY[i] == y)
            gameOver = true;

    if (x == fruitX && y == fruitY)
    {
        score += 10;
        fruitX = rand() % width;
        fruitY = rand() % height;
        nTail++;
    }
}

int main()
{
    Setup();

    while (!gameOver)
    {
        Draw();
        Input();
        Logic();
        Sleep(50);
    }

    return 0;
}
```

In this code, we use the console interface to build a simple Snake game. The game uses the arrow keys to control the snake's movement, and the goal is to eat the fruit without running into the walls or the tail. 

The game is built using a series of functions. We start with the `Setup()` function to initialize the game state and then move onto the `Draw()`, `Input()`, and `Logic()` functions. The `Draw()` function is used to display the game board on the console, while the `Input()` function reads the user input from the keyboard. The `Logic()` function updates the game state, including the snake's movement, score, and checking for collisions.

The most complex part of the code is the `Logic()` function, which computes the snake's movement and checks for collisions. We keep track of the snake's position using a pair of arrays `tailX` and `tailY`, which represent the positions of each segment of the snake's tail. We update these arrays as the snake moves, removing the tail end and adding a new segment to the front. 

The code also uses the `Sleep()` function to pause the program for a short period of time at the end of each game loop, to prevent the game from running too fast.

Note that this code is not optimized and may have bugs or limitations. It is meant to serve as an example of how to build a simple Snake game in C++.
